form:Form.form:Scripts:
		var c_tipo, c_letra, l_formato_nro;

function onload()
{
	Ctrl('lbl_titulo').SetText(Ctrl('titulo').GetXValue());

	if(Ctrl('main').GetMode()!='SHOW')
	{	
		if(Ctrl('lv_conceptos').TotalRowsCount()==0 && Ctrl('lv_impuestos').TotalRowsCount()==0)
		{					
			CtrlEnabled('oi_tipo_comprob', true);			
		}
		else
		{
			CtrlEnabled('oi_tipo_comprob', false);			
		}

		tipo_comprob_onchange();			
	}
}


function get_tipo_comprob()
{
	var oi_tipo_comprob = Ctrl('oi_tipo_comprob').GetXValue();
	var xmlParam = new NomadXML('DATA');
	xmlParam.SetAttr('oi_tipo_comprob',oi_tipo_comprob);	    
	var nSQL = GetProxy().SQLService();		
	objTipoComp = nSQL.GetOBJ(Ctrl('main').getResource('GetTipoComp'), xmlParam.ToString());
	l_formato_nro = objTipoComp.l_formato_nro;
	c_tipo = objTipoComp.c_tipo;
	c_letra = objTipoComp.c_letra;
}


function get_tipo_doc()
{
	var oi_tipo_doc = Ctrl('oi_tipo_doc').GetXValue();
	var xmlParam = new NomadXML('DATA');
	xmlParam.SetAttr('oi_tipo_doc',oi_tipo_doc);	    
	var nSQL = GetProxy().SQLService();		
	objTipoComp = nSQL.GetOBJ(Ctrl('main').getResource('GetTipoDoc'), xmlParam.ToString());
	return objTipoComp.c_tipo_doc;	
}


function habilitar_controles()
{
	if(c_tipo=='NN')
	{		
		Ctrl('oi_tipo_doc').SetCValue('');
		CtrlEnabled('oi_tipo_doc', false);
		Ctrl('c_nro_doc').SetCValue('');
		CtrlEnabled('c_nro_doc', false);
	}
	else
	{
		CtrlEnabled('oi_tipo_doc', true);
		CtrlEnabled('c_nro_doc', true);
	}

	if(c_letra=='X')
	{		
		Ctrl('oi_plan').SetCValue('');
		CtrlEnabled('oi_plan', false);
		Ctrl('d_cae').SetCValue('');
		CtrlEnabled('d_cae', false);
		Ctrl('f_cae').SetCValue('');
		CtrlEnabled('f_cae', false);
	}
	else
	{
		CtrlEnabled('oi_plan', true);
		CtrlEnabled('d_cae', true);	
		CtrlEnabled('f_cae', true);	
	}
}


function tipo_comprob_onchange()
{
	if(Ctrl('main').GetMode()!='SHOW')
	{
		if(Ctrl('oi_tipo_comprob').GetXValue()!='')
		{			
			get_tipo_comprob();
			habilitar_controles();			
		}	
	}
}


function addConcepto()
{	
	if(Ctrl('oi_tipo_comprob').GetXValue()=='')
	{
		alert('Para agregar conceptos indique un tipo de comprobante.');
		return false;	
	}		
	return true;
}


function addImpuesto()
{	
	if(Ctrl('oi_tipo_comprob').GetXValue()=='')
	{
		alert('Para agregar impuestos indique un tipo de comprobante.');
		return false;	
	}
	if(c_letra=='X')
	{
		alert('No es posible agregar impuestos para el tipo de comprobante seleccionado.');
		return false;
	}			
	return true;
}


function onvalidate(pObj)
{
	if(Ctrl('main').GetMode()!='SHOW')
	{	
		if(Ctrl('lv_conceptos').TotalRowsCount()==0)
		{
			pObj.SetError("Debe ingresar al menos un concepto de gasto.");
			return false;		
		}
	}
	return true;
}


function validarNroComp(pObj)
{
	if(Ctrl('main').GetMode()!='SHOW')
	{
		if(Ctrl('oi_tipo_comprob').GetXValue()!='')
		{	  
		  if (l_formato_nro == 1)
		  {
		  	var nroComp = Ctrl('c_nro_comp').GetXValue().toString();
		  	var regexp = /^\d{4}-\d{8}$/;
				if(!regexp.test(nroComp))
				{		
					pObj.SetError("El número de comprobante debe tener formato: 4 dígitos, guión, 8 dígitos. Por ejemplo: 9999-99999999.");
					return false;
				}  
		  }
		}
	}
	return true;
}


function validarOiPlan(pObj)
{
	if(Ctrl('main').GetMode()!='SHOW')
	{
		if(Ctrl('oi_tipo_comprob').GetXValue()!='')
		{
			if (c_letra!='X' && pObj.GetXValue()=='')
			{
				pObj.SetError('El valor es requerido.');
				return false;			
			}	
		}
	}
	return true;
}


function validarRequerido(pObj)
{
	if(Ctrl('main').GetMode()!='SHOW')
	{
		if(Ctrl('oi_tipo_comprob').GetXValue()!='')
		{
			if (c_tipo!='NN' && pObj.GetXValue()=='')
			{
				pObj.SetError('El valor es requerido.');
				return false;			
			}	
		}
	}
	return true;
}


function validarNroDoc(pObj) 
{
	if(Ctrl('main').GetMode()!='SHOW')
	{
		if(Ctrl('oi_tipo_comprob').GetXValue()!='')
		{
			if (c_tipo!='NN')			
			{
				if (pObj.GetXValue()=='')
				{
					pObj.SetError('El valor es requerido.');
					return false;			
				}				

				if (Ctrl('oi_tipo_doc').GetXValue!='')
				{					
					var c_tipo_doc = get_tipo_doc();					
				  if (c_tipo_doc=='80' || c_tipo_doc=='86')
				  {
				  	if(!validarCUIT(pObj))
				  		return false;
				  }
				}

				return validarComprobante(pObj);


			}
		}		
	}

	return true;
}


function validarCUIT(pObj)
{
	var cuit = pObj.GetXValue();
	if (!(cuit.match(/^\d{2}\-\d{8}\-\d{1}$/)))
	{
		pObj.SetError('El CUIT debe tener el siguiente formato: XX-XXXXXXXX-X');			
		return false;
	}	

	cuit_rearmado = '';
	for (i=0; i<cuit.length; i++)
	{   
		caracter = cuit.charAt(i);
	  if (caracter.charCodeAt(0) >= 48 && caracter.charCodeAt(0) <= 57)
	  {
	  	cuit_rearmado += caracter;
	  }
	}	  
	cuit = cuit_rearmado;

	//Si no estan todos los digitos
	if (cuit.length != 11)
	{		
	  pObj.SetError('CUIT Menor a 11 Caracteres');	        
	  return false;
	}


  x=i=dv=0;

  //Multiplico los dígitos.
  var vector = new Array(10);
  vector[0] = cuit.charAt(0) * 5;
  vector[1] = cuit.charAt(1) * 4;
  vector[2] = cuit.charAt(2) * 3;
  vector[3] = cuit.charAt(3) * 2;
  vector[4] = cuit.charAt(4) * 7;
  vector[5] = cuit.charAt(5) * 6;
  vector[6] = cuit.charAt(6) * 5;
  vector[7] = cuit.charAt(7) * 4;
  vector[8] = cuit.charAt(8) * 3;
  vector[9] = cuit.charAt(9) * 2;

  // Suma cada uno de los resultado.
  for(i=0; i<=9; i++)
  {
  	x += vector[i];
  }

  dv = (11 - (x % 11)) % 11;
  if (dv != cuit.charAt(10))
  {
    pObj.SetError('CUIT Inválido'); 
		return false;
  }



	return true;

	/*if (!esCuit)
	{
		pObj.SetError('CUIT Inválido'); 
		return false;
	}*/
}


//Edita concepto seleccionado
function btnEditConc_onclick()
{	
	if(Ctrl('lv_conceptos').TotalRowsCount()==0)
	{	
		alert("No hay conceptos cargados.");
		return false; 
	}

  return true; 
}


//Borra concepto seleccionado
function btnDelConc_onclick()
{
	if(Ctrl('lv_conceptos').TotalRowsCount()==0)
	{
		alert("No hay conceptos cargados.");
		return false;
	}

	var confirma = confirm("¿Está seguro que desea eliminar el concepto seleccionado?");
