function validarComprobante(pObj)
{
	if(Ctrl('main').GetMode()!='SHOW')
	{
		var xmlParam = new NomadXML('PARAM');
		xmlParam.SetAttr('oi_tipo_doc',Ctrl('oi_tipo_doc').GetXValue());
		xmlParam.SetAttr('oi_tipo_comprob',Ctrl('oi_tipo_comprob').GetXValue());
		xmlParam.SetAttr('c_nro_doc',Ctrl('c_nro_doc').GetXValue());
		xmlParam.SetAttr('c_nro_comp',Ctrl('c_nro_comp').GetXValue());

		var nSQL = GetProxy().SQLService();		
		var objCompNeg = nSQL.GetOBJ(Ctrl('main').getResource('validar_comprobante'), xmlParam.ToString());

		if(objCompNeg.l_existe!=0)
		{
			pObj.SetError("El Tipo y Número de Comprobante ya ha sido registrado para el mismo Proveedor (Tipo y Número de Documento)");
			return false;
		}
		else
			return true;
	}
}

qry:select.qry:xquery:
					for $r in sql('
			SELECT 
				COUNT(COMP.oi_comp_rendicion) as CONT
			FROM 
			  LEG06_COMPS_RENDICION as COMP			
			WHERE  			 
				COMP.oi_tipo_doc = {#SOURCE:@oi_tipo_doc} 
        AND COMP.c_nro_doc = {#SOURCE:@c_nro_doc}
        AND COMP.oi_tipo_comprob = {#SOURCE:@oi_tipo_comprob}
        AND COMP.c_nro_comp = {#SOURCE:@c_nro_comp} 
   	')/ROWS/ROW
